static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Conv2dMinTanhTanhCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);
    const bool hasBias = (context->GetNumInputs() >= 3) && (context->GetInputShape(2)->GetShapeSize() > 0);

    // Expect x: [N, Cin, H, W], weight: [Cout, Cin, Kh, Kw]
    const auto &xs = x_shape->GetOriginShape();
    const auto &ws = w_shape->GetOriginShape();

    const uint32_t N   = static_cast<uint32_t>(xs.GetDim(0));
    const uint32_t Cin = static_cast<uint32_t>(xs.GetDim(1));
    const uint32_t H   = static_cast<uint32_t>(xs.GetDim(2));
    const uint32_t W   = static_cast<uint32_t>(xs.GetDim(3));

    const uint32_t Cout = static_cast<uint32_t>(ws.GetDim(0));
    const uint32_t Kh   = static_cast<uint32_t>(ws.GetDim(2));
    const uint32_t Kw   = static_cast<uint32_t>(ws.GetDim(3));

    // Fixed: stride=1, padding=0, dilation=1
    const uint32_t HOut = (H >= Kh) ? (H - Kh + 1) : 0;
    const uint32_t WOut = (W >= Kw) ? (W - Kw + 1) : 0;

    // We choose tile width = 1 for simplicity and robustness
    const uint32_t tileW = 1;

    // Grid over rows (N * HOut)
    const uint32_t totalRows = (HOut == 0 || WOut == 0) ? 0u : (N * HOut);
    uint32_t blockDim = totalRows;
    if (blockDim == 0) blockDim = 1;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_N(N);
    tiling.set_Cin(Cin);
    tiling.set_H(H);
    tiling.set_W(W);
    tiling.set_Cout(Cout);
    tiling.set_Kh(Kh);
    tiling.set_Kw(Kw);
    tiling.set_HOut(HOut);
    tiling.set_WOut(WOut);
    tiling.set_tileW(tileW);
    tiling.set_blockDim(blockDim);
    tiling.set_hasBias(hasBias ? 1u : 0u);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

